const A = globalThis;
function getLedger() {
  let a = game.actors.find(x => x.getFlag("ashen", "role") === "souls");
  if (!a) a = game.actors.getName("Bonfire Ledger");
  if (!a) ui.notifications.warn("Ashen: no 'Bonfire Ledger' actor found. Import the Ashen actors pack.");
  return a;
}
async function getSouls(a, k) { return Number(a?.getFlag("ashen", k) ?? 0); }
async function setSouls(a, k, v) { return a.setFlag("ashen", k, Math.max(0, Math.round(v))); }
async function askNumber(title, label) {
  const content = '<form><div class="form-group"><label>' + label + '</label>' +
    '<input type="number" name="n" value="0" autofocus/></div></form>';
  return await new Promise((resolve) => {
    new Dialog({
      title, content,
      buttons: {
        ok: { label: "OK", callback: (h) => resolve(Number(h[0].querySelector('[name=n]').value) || 0) },
        cancel: { label: "Cancel", callback: () => resolve(null) }
      },
      default: "ok", close: () => resolve(null)
    }).render(true);
  });
}
// Active Effect helpers (dnd5e v5 schema).
async function createEffect(actor, label, icon, changes = []) {
  if (!actor) return;
  const existing = actor.effects.find(e => e.name === label);
  if (existing) return existing;
  return await actor.createEmbeddedDocuments("ActiveEffect", [{
    name: label, icon, origin: actor.uuid,
    disabled: false, changes: changes.map(([k, v]) => ({ key: k, mode: 2, value: v }))
  }]);
}
async function removeEffectByName(actor, label) {
  if (!actor) return;
  const fx = actor.effects.find(e => e.name === label);
  if (fx) await fx.delete();
}
async function removeAllAshenEffects(actor) {
  if (!actor) return;
  const fx = actor.effects.filter(e => ["Exhaustion (Auto)", "Embered", "Frostbite (Build-up)"].includes(e.name));
  if (fx.length) await actor.deleteEmbeddedDocuments("ActiveEffect", fx.map(e => e.id));
}


const a = getLedger();
const COST = { 4: 500, 5: 800, 6: 1200, 7: 1800, 8: 2600, 9: 3600, 10: 5000 };
const party = game.actors.filter(x => x.type === "character");
if (!party.length) return ui.notifications.warn("Ashen: no player characters found. Import the Ashen pregens pack.");

// v13-safe picker: resolve() is wired into each button AT CONSTRUCTION (the old version mutated
// button callbacks after the Dialog was built, which the v13 DialogV2 shim ignores — so picking
// did nothing). A <select> also handles the long upgrade list far better than a wall of buttons.
function dialogSelect(title, intro, options, dflt) {
  const opts = options.map(o => '<option value="' + o.value + '"' + (String(o.value) === String(dflt) ? ' selected' : '') + '>' + o.label + '</option>').join("");
  const content = intro + '<form><div class="form-group"><label>Choose</label><select name="pick" style="width:100%">' + opts + '</select></div></form>';
  return new Promise((resolve) => {
    new Dialog({
      title, content,
      buttons: {
        ok: { icon: '<i class="fas fa-check"></i>', label: "Apply", callback: (html) => resolve(html[0].querySelector('[name=pick]')?.value ?? null) },
        skip: { icon: '<i class="fas fa-forward"></i>', label: "Skip", callback: () => resolve(null) }
      },
      default: "ok", close: () => resolve(null)
    }, { width: 480 }).render(true);
  });
}

async function grantPick(pc, name) {
  let item = game.items.getName(name);
  if (!item) { for (const p of game.packs) { if (p.documentName !== "Item") continue; const e = p.index.getName?.(name); if (e) { item = await p.getDocument(e._id); break; } } }
  if (!item) { ui.notifications.warn("Ashen: pick '" + name + "' not found; add it from the Level-Up cards manually."); return; }
  await pc.createEmbeddedDocuments("Item", [item.toObject()]);
}

const levelOpts = Object.entries(COST).map(([l, c]) => ({ label: "→ Level " + l + "  (" + c + " souls)", value: l }));
const lvlPick = await dialogSelect("Party Level Up at the Fire Keeper",
  "<p>The whole party (<b>" + party.length + "</b> characters) ascends. Choose the level to purchase:</p>",
  levelOpts, "4");
if (!lvlPick) return;
const lvl = Number(lvlPick);
const cost = COST[lvl];

// Souls economy is OPTIONAL — only enforced if a Bonfire Ledger exists. Without one, leveling is a DM override.
let spend = 0, banked = 0;
if (a) {
  banked = await getSouls(a, "banked");
  spend = cost;
  if (cost > banked) {
    const ok = await Dialog.confirm({
      title: "Not enough banked souls",
      content: "<p>Level " + lvl + " costs <b>" + cost + "</b> banked souls, but the party has <b>" + banked + "</b>.</p>" +
        "<p>Level the party anyway as a <b>DM override</b> (no souls spent)?</p>",
      yes: () => true, no: () => false, defaultYes: false
    });
    if (!ok) return;
    spend = 0;
  }
  await setSouls(a, "banked", banked - spend);
}

const PICKS = ["Attribute: Vigor +1","Attribute: Strength +1","Attribute: Dexterity +1","Attribute: Endurance +1","Attribute: Intelligence +1","Attribute: Faith +1","Attribute: Attunement +1","Dexterity: AC Milestone (+1 AC)","Weapon Art: Stomp","Weapon Art: Perseverance","Weapon Art: Spin Slash","Weapon Art: Charge","Weapon Art: Quickstep","Weapon Art: Leo Riposte","Weapon Art: Steady Chant","Weapon Art: Crystallize","Weapon Art: Pyromancer's Fervor","Weapon Art: Sage's Focus","Weapon Art: Estus Mastery"];
const pickOpts = PICKS.map(n => ({ label: n, value: n }));
const summary = [];
for (const pc of party) {
  const cls = pc.items.find(i => i.type === "class");
  if (cls) await cls.update({ "system.levels": (cls.system.levels || 1) + 1 });
  const pick = await dialogSelect(pc.name + ": choose an upgrade (now L" + lvl + ")",
    "<p>Pick <b>" + pc.name + "</b>'s upgrade card (auto-applied to their sheet):</p>",
    pickOpts, PICKS[0]);
  if (pick) await grantPick(pc, pick);
  summary.push("<b>" + pc.name + "</b>" + (pick ? " — " + pick : " — (skipped)"));
}
ChatMessage.create({ content: "<b>The party ascends to Level " + lvl + "</b> (" + (spend ? "-" + spend + " souls" : "DM override — no souls spent") + ")." + (a ? " Banked = " + (banked - spend) + "." : "") + "<br>" + summary.join("<br>") });
